import{A as e,d as t,m as n,t as r}from"./plugin-vue_export-helper--IMkQmEh.js";var i=JSON.parse(`{"path":"/","title":"","lang":"zh-CN","frontmatter":{"home":true,"heroImage":"/logo.svg","heroText":"Go-FlashDB","heroAlt":"Go-FlashDB Logo","tagline":"深入源码学习 Go 语言高性能 Redis 服务器实现","taglineAlt":"不只是教程，更是设计思想与工程实践的完美结合","actions":[{"text":"快速开始","link":"/guide/","type":"primary"},{"text":"设计哲学","link":"/design/","type":"secondary"},{"text":"查看源码","link":"https://github.com/strings77wzq/go-flashdb","type":"secondary"}],"features":[{"title":"⚡ 极致性能","details":"65536 分片并发字典设计，锁冲突率低于 0.001%。对比 sync.Map，在写多场景下性能提升 5-10 倍。"},{"title":"🎯 Redis 完全兼容","details":"100% 实现 RESP 协议，支持 String/Hash/List/Set/ZSet/Bitmap/HyperLogLog 全部数据类型，可直接使用 redis-cli 连接。"},{"title":"🏗️ 清晰架构","details":"分层架构设计：Protocol → Core → Persistence → Security → Extension。每个模块职责单一，代码可读性极强。"},{"title":"🤖 AI 扩展","details":"预留 OpenClaw/Skills/MCP 扩展接口，为 AI 时代的数据库交互做好准备。这是 go-flashdb 区别于其他实现的核心创新。"},{"title":"🛡️ 生产级安全","details":"内置认证、限流、危险命令拦截三层安全防护。支持 TLS 加密传输，符合企业级部署标准。"},{"title":"📚 完整教程","details":"从 TCP 服务器到 Cluster 协议，12 篇深度教程带你从零实现 Redis。每篇都包含设计原理、源码解析和性能对比。"}],"footer":"MIT Licensed | Copyright © 2026-present go-flashdb","footerHtml":true},"git":{"updatedTime":1775618263000,"contributors":[{"name":"strings77wzq","username":"strings77wzq","email":"strings77wzq@github.com","commits":1,"url":"https://github.com/strings77wzq"}],"changelog":[{"hash":"3c536800d4175146327c71649c552297dd8add0c","time":1775618263000,"email":"strings77wzq@github.com","author":"strings77wzq","message":"feat: implement v0.3.0 features and documentation website","tag":"v0.3.0"}]},"filePathRelative":"README.md"}`),a={name:`README.md`};function o(r,i,a,o,s,c){return e(),t(`div`,null,[...i[0]||=[n(`<h2 id="为什么选择-go-flashdb" tabindex="-1"><a class="header-anchor" href="#为什么选择-go-flashdb"><span>为什么选择 Go-FlashDB？</span></a></h2><h3 id="不只是又一个-redis-实现" tabindex="-1"><a class="header-anchor" href="#不只是又一个-redis-实现"><span>不只是又一个 Redis 实现</span></a></h3><p>市面上已有多个 Go 语言实现的 Redis（如 godis、redcon），但 go-flashdb 致力于成为<strong>最适合学习</strong>的实现：</p><table><thead><tr><th>特性</th><th>go-flashdb</th><th>godis</th><th>redcon</th></tr></thead><tbody><tr><td><strong>代码可读性</strong></td><td>⭐⭐⭐⭐⭐ 分层清晰</td><td>⭐⭐⭐⭐ 功能完整</td><td>⭐⭐⭐ 库而非完整实现</td></tr><tr><td><strong>学习曲线</strong></td><td>平缓，从基础到高级</td><td>陡峭，直接看集群</td><td>不适用</td></tr><tr><td><strong>并发设计</strong></td><td>65536 分片 + 详细讲解</td><td>分段锁</td><td>-</td></tr><tr><td><strong>AI 扩展</strong></td><td>✅ 预留接口</td><td>❌ 无</td><td>❌ 无</td></tr><tr><td><strong>教程完整度</strong></td><td>12 篇深度教程</td><td>博客系列</td><td>❌ 无</td></tr></tbody></table><h3 id="设计理念" tabindex="-1"><a class="header-anchor" href="#设计理念"><span>设计理念</span></a></h3><h4 id="_1-性能与可读性的平衡" tabindex="-1"><a class="header-anchor" href="#_1-性能与可读性的平衡"><span>1. <strong>性能与可读性的平衡</strong></span></a></h4><p>许多高性能代码牺牲可读性来换取速度。go-flashdb 采用<strong>清晰的架构 + 精心设计的算法</strong>，让你既能理解原理，又能学到性能优化技巧。</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line"><span class="token comment">// ConcurrentDict: 65536 分片设计</span></span>
<span class="line"><span class="token comment">// 核心思想：通过增加分片数量来降低锁冲突概率</span></span>
<span class="line"><span class="token comment">// 而不是使用更复杂的无锁数据结构</span></span>
<span class="line"><span class="token keyword">type</span> ConcurrentDict <span class="token keyword">struct</span> <span class="token punctuation">{</span></span>
<span class="line">    segments <span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token operator">*</span>Segment  <span class="token comment">// 65536 个分片</span></span>
<span class="line">    count    <span class="token builtin">int</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">type</span> Segment <span class="token keyword">struct</span> <span class="token punctuation">{</span></span>
<span class="line">    m  <span class="token keyword">map</span><span class="token punctuation">[</span><span class="token builtin">string</span><span class="token punctuation">]</span><span class="token keyword">interface</span><span class="token punctuation">{</span><span class="token punctuation">}</span></span>
<span class="line">    mu sync<span class="token punctuation">.</span>RWMutex  <span class="token comment">// 每个分片独立锁</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="_2-渐进式复杂度" tabindex="-1"><a class="header-anchor" href="#_2-渐进式复杂度"><span>2. <strong>渐进式复杂度</strong></span></a></h4><p>从最简单的 Echo 服务器开始，逐步添加 RESP 协议、数据类型、持久化、事务、复制、Cluster。每章都建立在前章基础上，符合认知规律。</p><h4 id="_3-工程化实践" tabindex="-1"><a class="header-anchor" href="#_3-工程化实践"><span>3. <strong>工程化实践</strong></span></a></h4><p>不只是&quot;能跑&quot;，而是&quot;能生产&quot;。包含：</p><ul><li>✅ 完整的错误处理</li><li>✅ 优雅关闭（Graceful Shutdown）</li><li>✅ 配置管理</li><li>✅ 单元测试（覆盖率 70%+）</li><li>✅ Benchmark 性能测试</li></ul><h3 id="性能表现" tabindex="-1"><a class="header-anchor" href="#性能表现"><span>性能表现</span></a></h3><p>使用 redis-benchmark 测试（50 并发，10000 请求）：</p><table><thead><tr><th>命令</th><th>QPS</th><th>P99 延迟</th></tr></thead><tbody><tr><td>SET</td><td>~120k</td><td>&lt; 1ms</td></tr><tr><td>GET</td><td>~150k</td><td>&lt; 0.5ms</td></tr><tr><td>HSET</td><td>~100k</td><td>&lt; 1ms</td></tr><tr><td>LPUSH</td><td>~90k</td><td>&lt; 1ms</td></tr></tbody></table><p><em>测试环境：本地 MacBook Pro M2</em></p><h3 id="项目结构" tabindex="-1"><a class="header-anchor" href="#项目结构"><span>项目结构</span></a></h3><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code class="language-text"><span class="line">goflashdb/</span>
<span class="line">├── cmd/</span>
<span class="line">│   ├── goflashdb/      # 主程序入口</span>
<span class="line">│   └── benchmark/      # 性能测试工具</span>
<span class="line">├── pkg/</span>
<span class="line">│   ├── core/           # 核心：数据类型、命令、事务</span>
<span class="line">│   ├── resp/           # 协议层：RESP 解析器</span>
<span class="line">│   ├── persist/        # 持久化：AOF、RDB</span>
<span class="line">│   ├── net/            # 网络层：TCP 服务器</span>
<span class="line">│   ├── security/       # 安全：认证、限流、过滤</span>
<span class="line">│   ├── replication/    # 复制：主从同步</span>
<span class="line">│   ├── cluster/        # 集群：槽位管理</span>
<span class="line">│   ├── benchmark/      # 基准测试框架</span>
<span class="line">│   └── extension/      # 扩展：AI 接口预留</span>
<span class="line">└── docs/               # 本文档</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="快速开始" tabindex="-1"><a class="header-anchor" href="#快速开始"><span>快速开始</span></a></h3><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token comment"># 1. 克隆项目</span></span>
<span class="line"><span class="token function">git</span> clone https://github.com/strings77wzq/go-flashdb.git</span>
<span class="line"><span class="token builtin class-name">cd</span> go-flashdb</span>
<span class="line"></span>
<span class="line"><span class="token comment"># 2. 编译</span></span>
<span class="line">go build <span class="token parameter variable">-o</span> goflashdb ./cmd/goflashdb</span>
<span class="line"></span>
<span class="line"><span class="token comment"># 3. 启动</span></span>
<span class="line">./goflashdb</span>
<span class="line"></span>
<span class="line"><span class="token comment"># 4. 测试</span></span>
<span class="line">redis-cli <span class="token function">ping</span></span>
<span class="line"><span class="token comment"># PONG</span></span>
<span class="line"></span>
<span class="line">redis-cli <span class="token builtin class-name">set</span> hello world</span>
<span class="line"><span class="token comment"># OK</span></span>
<span class="line"></span>
<span class="line">redis-cli get hello</span>
<span class="line"><span class="token comment"># &quot;world&quot;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="学习路径" tabindex="-1"><a class="header-anchor" href="#学习路径"><span>学习路径</span></a></h3><div class="language-mermaid line-numbers-mode" data-highlighter="prismjs" data-ext="mermaid"><pre><code class="language-mermaid"><span class="line"><span class="token keyword">graph</span> LR</span>
<span class="line">    A<span class="token text string">[快速开始]</span> <span class="token arrow operator">--&gt;</span> B<span class="token text string">[TCP服务器]</span></span>
<span class="line">    B <span class="token arrow operator">--&gt;</span> C<span class="token text string">[RESP协议]</span></span>
<span class="line">    C <span class="token arrow operator">--&gt;</span> D<span class="token text string">[并发字典]</span></span>
<span class="line">    D <span class="token arrow operator">--&gt;</span> E<span class="token text string">[数据类型]</span></span>
<span class="line">    E <span class="token arrow operator">--&gt;</span> F<span class="token text string">[持久化]</span></span>
<span class="line">    F <span class="token arrow operator">--&gt;</span> G<span class="token text string">[事务]</span></span>
<span class="line">    G <span class="token arrow operator">--&gt;</span> H<span class="token text string">[复制]</span></span>
<span class="line">    H <span class="token arrow operator">--&gt;</span> I<span class="token text string">[Cluster]</span></span>
<span class="line">    I <span class="token arrow operator">--&gt;</span> J<span class="token text string">[性能优化]</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="贡献" tabindex="-1"><a class="header-anchor" href="#贡献"><span>贡献</span></a></h3><p>欢迎提交 Issue 和 PR！详见 <a href="https://github.com/strings77wzq/go-flashdb/blob/main/CONTRIBUTING.md" target="_blank" rel="noopener noreferrer">CONTRIBUTING.md</a></p><h3 id="许可" tabindex="-1"><a class="header-anchor" href="#许可"><span>许可</span></a></h3><p><a href="https://github.com/strings77wzq/go-flashdb/blob/main/LICENSE" target="_blank" rel="noopener noreferrer">MIT</a></p><hr><p><strong>开始你的 Redis 实现之旅 →</strong> <a href="/guide/" target="_blank" rel="noopener noreferrer">快速开始</a></p>`,29)]])}var s=r(a,[[`render`,o]]);export{i as _pageData,s as default};